export const getUploadFileUrl = () => {
  return `/api/upload`;
};

export const uploadFile = async (
  uploadFileBody: UploadFileBody,
  options?: RequestInit,
): Promise<UploadResponse> => {
  const formData = new FormData();
  formData.append(`file`, uploadFileBody.file);
  if (uploadFileBody.brandId !== undefined) {
    formData.append(`brandId`, uploadFileBody.brandId);
  }
  if (uploadFileBody.type !== undefined) {
    formData.append(`type`, uploadFileBody.type);
  }

  return customFetch<UploadResponse>(getUploadFileUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

